def load_config(repo_path: Path | None = None, profile: str | None = None) -> GlitchLabConfig:
    base_data = yaml.safe_load(config_path.read_text()) or {}
    if profile is not None:
        profile_path = repo_root / 'glitchlab' / 'profiles' / f'{profile}.yaml'
        if not profile_path.exists(): raise FileNotFoundError(f'Profile config not found: {profile_path}')
        base_data = _deep_merge(base_data, yaml.safe_load(profile_path.read_text()) or {})

def run(..., surgical: bool = typer.Option(False, '--surgical', help='Run surgical pipeline')):
    controller = Controller(..., surgical=surgical)

def interactive(..., surgical: bool = typer.Option(False, '--surgical', help='Run surgical pipeline')):
    controller = Controller(..., surgical=surgical)

class Controller:
    def __init__(..., surgical: bool = False):
        self.surgical = surgical

    def run(...):
        ctx = RunContext(..., surgical=self.surgical)
        if self.surgical:
            ctx.surgical = True
            surgical_config = load_config(self.repo_path, profile='surgical')
            ctx.config.pipeline = surgical_config.pipeline
            ctx.config.limits.max_fix_attempts = 1
            return self._execute_pipeline(ctx, task, pipeline_state, ...)
